import React, { useState } from 'react';
import Dashboard from './Dashboard';
import { uploadDNA, submitManualData } from './api';

function App() {
    const [analysisData, setAnalysisData] = useState(null);
    const [isLoading, setIsLoading] = useState(false);
    const [view, setView] = useState('choice'); // 'choice', 'dna', or 'manual'
    const [error, setError] = useState(null);

    // Manual Form State
    const [goal, setGoal] = useState('Energy');
    const [symptoms, setSymptoms] = useState([]);

    const handleFileUpload = async (event) => {
        const file = event.target.files[0];
        if (!file) return;
        setIsLoading(true);
        try {
            const response = await uploadDNA(file);
            setAnalysisData(response.data);
        } catch (err) { setError("Backend connection failed."); }
        finally { setIsLoading(false); }
    };

    const handleManualSubmit = async () => {
        setIsLoading(true);
        try {
            const response = await submitManualData({ goal, symptoms });
            setAnalysisData(response.data);
        } catch (err) { setError("Backend connection failed."); }
        finally { setIsLoading(false); }
    };

    const toggleSymptom = (s) => {
        setSymptoms(prev => prev.includes(s) ? prev.filter(i => i !== s) : [...prev, s]);
    };

    return (
        <div style={styles.container}>
            <header style={styles.header}>
                <h1 style={styles.title}>NutriGen<span style={{color: '#38a169'}}>.</span></h1>
                <p style={styles.subtitle}>Genetic & Lifestyle Nutritional Analysis</p>
            </header>

            <main>
                {analysisData ? (
                    <Dashboard data={analysisData} onReset={() => {setAnalysisData(null); setView('choice');}} />
                ) : view === 'choice' ? (
                    <div style={styles.choiceGrid}>
                        <div style={styles.optionCard} onClick={() => setView('dna')}>
                            <h3>🧬 DNA Upload</h3>
                            <p>Analyze raw data from 23andMe or Ancestry.</p>
                        </div>
                        <div style={styles.optionCard} onClick={() => setView('manual')}>
                            <h3>📝 Health Quiz</h3>
                            <p>No DNA data? Get insights based on symptoms.</p>
                        </div>
                    </div>
                ) : view === 'dna' ? (
                    <div style={styles.card}>
                        <h3>Upload DNA File</h3>
                        <input type="file" onChange={handleFileUpload} id="dna-file" hidden />
                        <label htmlFor="dna-file" style={styles.btn}>
                            {isLoading ? "Analyzing..." : "Select .txt File"}
                        </label>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Go Back</button>
                    </div>
                ) : (
                    <div style={styles.card}>
                        <h3>Health Assessment</h3>
                        <div style={{textAlign: 'left', maxWidth: '400px', margin: '0 auto'}}>
                            <label>Primary Goal:</label>
                            <select value={goal} onChange={(e) => setGoal(e.target.value)} style={styles.input}>
                                <option>Energy</option>
                                <option>Immunity</option>
                                <option>Weight Management</option>
                            </select>
                            
                            <label>Current Symptoms:</label>
                            <div style={{display: 'flex', gap: '10px', flexWrap: 'wrap', margin: '10px 0'}}>
                                {['Fatigue', 'Stress', 'Poor Sleep', 'Muscle Cramps'].map(s => (
                                    <button 
                                        key={s} 
                                        onClick={() => toggleSymptom(s)}
                                        style={symptoms.includes(s) ? styles.tagActive : styles.tag}
                                    >
                                        {s}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <button onClick={handleManualSubmit} style={styles.btn}>
                            {isLoading ? "Generating..." : "Get Recommendations"}
                        </button>
                        <button onClick={() => setView('choice')} style={styles.backLink}>Go Back</button>
                    </div>
                )}
                {error && <p style={{color: 'red'}}>{error}</p>}
            </main>
        </div>
    );
}

const styles = {
    container: { maxWidth: '1000px', margin: '0 auto', padding: '50px 20px', fontFamily: 'sans-serif', textAlign: 'center' },
    header: { marginBottom: '50px' },
    title: { fontSize: '2.5rem', margin: 0 },
    subtitle: { color: '#666' },
    choiceGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' },
    optionCard: { padding: '40px', border: '1px solid #eee', borderRadius: '20px', cursor: 'pointer', transition: '0.2s', background: '#f9f9f9' },
    card: { background: '#f9f9f9', padding: '40px', borderRadius: '20px', border: '1px solid #eee' },
    btn: { background: '#1a202c', color: '#fff', padding: '12px 30px', borderRadius: '8px', cursor: 'pointer', border: 'none', display: 'block', margin: '20px auto' },
    input: { width: '100%', padding: '10px', margin: '10px 0', borderRadius: '5px', border: '1px solid #ddd' },
    tag: { padding: '5px 15px', borderRadius: '20px', border: '1px solid #ddd', background: '#fff', cursor: 'pointer' },
    tagActive: { padding: '5px 15px', borderRadius: '20px', border: '1px solid #38a169', background: '#e6fffa', cursor: 'pointer' },
    backLink: { background: 'none', border: 'none', color: '#666', cursor: 'pointer', textDecoration: 'underline' }
};

export default App;
